arguments.argument:
event_inherited()
if global.gamePaused=false
{
  if place_meeting(x,y,oNightmareEffect) {bulletSpeed=12}
  else {bulletSpeed=24}
  speed=bulletSpeed
  if x<view_xview[0]
    instance_destroy()
  if x>view_xview[0]+view_wview[0]
    instance_destroy()
  
  if isCollisionLeft(1)
    instance_destroy()
  if isCollisionRight(1)
    instance_destroy()
  if isCollisionBottom(1)
    instance_destroy()
  if isCollisionTop(1)
    instance_destroy()
  lifeTime-=1
  if lifeTime=0
    instance_destroy()
}
else
  speed=0
